#!/bin/bash
# Skill eval verifier — runs LLM judge against agent trajectory.
# Generated by benchflow skill-eval. Do not edit.
set -e

VERIFIER_DIR=/verifier
if [ ! -f "$VERIFIER_DIR/judge.py" ]; then
    VERIFIER_DIR=/tests
fi

cd "$VERIFIER_DIR"

# Run judge (anthropic/openai SDKs baked into Dockerfile)
python3 "$VERIFIER_DIR/judge.py"

# Copy reward to verifier output
cp "$VERIFIER_DIR/reward.txt" /logs/verifier/reward.txt

# Copy criterion-level rubric details where the skill-eval collector reads
# them (#406). judge.py writes judge_result.json beside itself; without this
# copy CaseResult.rubric_results was silently None even when the judge
# produced rich detail.
if [ -f "$VERIFIER_DIR/judge_result.json" ]; then
    cp "$VERIFIER_DIR/judge_result.json" /logs/verifier/judge_result.json
fi
